sp_widget.client_script:
api.controller = function($scope, spUtil) {
    var c = this;

    c.data = c.data || {};
    c.data.approvals = c.data.approvals || [];
    c.filteredApprovals = []; // New local array for bulletproof UI rendering

    c.currentPage = 1;
    c.pageSize = 6; 
    c.filter = 'pending';
    c.showModal = false;
    c.activeRejectId = '';

    // --- THE BULLETPROOF FILTER ENGINE ---
    c.updateLocalFilters = function() {
        var rawData = c.data.approvals || [];

        c.filteredApprovals = rawData.filter(function(item) {
            var state = item.state ? item.state.toLowerCase() : '';

            // 1. Force Status Filter locally (Overrides bad server responses)
            var matchStatus = true;
            if (c.filter === 'pending') {
                matchStatus = (state === 'requested' || state === 'pending');
            } else if (c.filter === 'processed') {
                matchStatus = (state === 'approved' || state === 'rejected' || state === 'processed');
            }

            // 2. Force Search Filter locally
            var matchSearch = true;
            if (c.searchQuery) {
                var term = c.searchQuery.toLowerCase();
                matchSearch = item.display_name && item.display_name.toLowerCase().includes(term);
            }

            return matchStatus && matchSearch;
        });
    };

    // Run the filter immediately on load
    c.updateLocalFilters();

    // Pagination Helpers
    c.getMin = function(a, b) { return Math.min(a, b); };
    c.getTotalPages = function() { return Math.ceil(c.filteredApprovals.length / c.pageSize) || 1; };
    c.prevPage = function() { if (c.currentPage > 1) c.currentPage--; };
    c.nextPage = function() { if (c.currentPage < c.getTotalPages()) c.currentPage++; };

    // Hybrid Action: Instantly filter local data, then fetch from server to sync
    c.setFilter = function(val) {
        c.filter = val;
        c.currentPage = 1; 
        c.updateLocalFilters(); // Instant visual snap

        c.server.get({action: 'fetch', filter: c.filter}).then(function(r) {
            c.data.approvals = r.data.approvals || [];
            c.updateLocalFilters(); // Background sync
        });
    };

    c.updateSearch = function() {
        c.currentPage = 1; 
        c.updateLocalFilters(); // Instant visual snap

        c.server.get({action: 'fetch', filter: c.filter, searchQuery: c.searchQuery}).then(function(r) {
            c.data.approvals = r.data.approvals || [];
            c.updateLocalFilters(); // Background sync
        });
    };

    c.approve = function(id) {
        c.server.get({action: 'approve', targetId: id}).then(function() {
            spUtil.addInfoMessage("Request Approved");
            c.setFilter(c.filter); 
        });
    };

    c.openRejectModal = function(id) {
        c.activeRejectId = id;
        c.rejectComment = '';
        c.showModal = true;
    };

    c.confirmReject = function() {
        c.server.get({
            action: 'reject', 
            targetId: c.activeRejectId, 
            comment: c.rejectComment
        }).then(function() {
            c.showModal = false;
            spUtil.addInfoMessage("Request Rejected"); 
            c.setFilter(c.filter); 
        });
    };
};

sp_widget.css:
/* --- Global Wrapper --- */
.sc-approval-wrapper {
  font-family: 'Poppins', 'Inter', system-ui, sans-serif;
  color: #1e293b;
  padding: 20px;
  display: flex;
  flex-direction: column;
  min-height: calc(100vh - 40px);
}

.sc-approval-panel {
  background: #ffffff;
  border-radius: 16px;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.03);
  margin-bottom: 24px;
  border: 1px solid #e2e8f0;
  display: flex;
  flex-direction: column;
  flex-grow: 1; 
  overflow: hidden;
}

/* --- Header & Search --- */
.sc-approval-header {
  padding: 20px 24px 16px 24px;
  background-color: #fbfcfe;
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: 16px;
}

.sc-approval-title {
  margin: 0;
  font-size: 18px;
  font-weight: 700;
  color: #1e293b;
}

.sc-approval-search {
  position: relative;
  display: flex;
  align-items: center;
  width: 100%;
  max-width: 300px;
}

.sc-approval-search-icon { position: absolute; left: 16px; color: #94a3b8; }

.sc-approval-input {
  width: 100%; height: 42px; padding: 0 16px 0 44px;
  border: 1px solid #cbd5e1; border-radius: 10px;
  font-size: 13px; color: #1e293b; transition: all 0.2s; font-family: inherit;
}

.sc-approval-input:focus { border-color: #1961ED; outline: none; box-shadow: 0 0 0 3px rgba(25, 97, 237, 0.1); }

/* --- HIGH VISIBILITY PILL TABS --- */
.sc-approval-tabs-container {
  padding: 0 24px 20px 24px;
  background-color: #fbfcfe;
  border-bottom: 1px solid #e2e8f0;
}

.sc-approval-tabs {
  display: inline-flex;
  background-color: #f1f5f9;
  padding: 6px;
  border-radius: 12px;
  border: 1px solid #e2e8f0;
  gap: 4px;
}

.sc-approval-tab {
  background: transparent;
  border: none;
  color: #64748b;
  font-weight: 600;
  font-size: 14px;
  padding: 10px 24px;
  border-radius: 8px;
  cursor: pointer;
  transition: all 0.2s;
  display: flex;
  align-items: center;
  gap: 8px;
  font-family: inherit;
}

.sc-approval-tab i { font-size: 15px; opacity: 0.8; }

.sc-approval-tab:hover:not(.active) { color: #1e293b; background: rgba(255, 255, 255, 0.6); }

.sc-approval-tab.active {
  background: #ffffff;
  color: #1961ED;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

/* --- Table --- */
.sc-approval-table-wrapper { width: 100%; overflow-x: auto; flex-grow: 1;}
.sc-approval-table { width: 100%; border-collapse: collapse; text-align: left; }

.sc-approval-table th { 
  background-color: #ffffff; color: #94a3b8; font-size: 12px; font-weight: 700; 
  text-transform: uppercase; padding: 16px 24px; border-bottom: 1px solid #e2e8f0; letter-spacing: 0.5px;
}

.sc-approval-table td { padding: 16px 24px; border-bottom: 1px solid #f1f5f9; font-size: 14px; vertical-align: middle;}
.sc-approval-table tbody tr { transition: background-color 0.2s; }
.sc-approval-table tbody tr:hover { background-color: #f8fafc; }

.sc-fw-bold { font-weight: 600; color: #1e293b; }
.sc-text-muted { color: #64748b; font-size: 13px; }

/* --- Badges --- */
.sc-badge {
  padding: 4px 10px; border-radius: 20px; font-size: 11px; font-weight: 700; 
  text-transform: uppercase; letter-spacing: 0.5px; display: inline-block; white-space: nowrap;
}

.badge-requested { background: #fef3c7; color: #b45309; } /* Amber */
.badge-approved { background: #dcfce7; color: #15803d; }  /* Green */
.badge-rejected { background: #fee2e2; color: #b91c1c; }  /* Red */

/* --- Action Buttons --- */
.sc-action-group { display: flex; gap: 8px; }

.sc-btn {
  border: none; border-radius: 8px; font-weight: 600; font-size: 12px;
  padding: 6px 12px; cursor: pointer; transition: all 0.2s; font-family: inherit;
  display: flex; align-items: center; gap: 6px;
}

.sc-btn-approve { background: #dcfce7; color: #15803d; border: 1px solid #bbf7d0;}
.sc-btn-approve:hover { background: #15803d; color: #ffffff; }

.sc-btn-reject { background: #ffffff; color: #b91c1c; border: 1px solid #fecaca;}
.sc-btn-reject:hover { background: #fee2e2; }

/* --- Empty State --- */
.sc-empty-state { text-align: center; padding: 60px 20px; color: #94a3b8; flex-grow: 1; display: flex; flex-direction: column; justify-content: center; align-items: center;}
.sc-empty-state i { font-size: 40px; margin-bottom: 12px; color: #cbd5e1; }
.sc-empty-state p { margin: 0; font-weight: 500; font-size: 14px; }

/* --- Pagination --- */
.sc-pagination-wrapper { 
  display: flex; justify-content: space-between; align-items: center; padding: 20px 24px; border-top: 1px solid #e2e8f0; background: #fff;
  margin-top: auto; 
}
.sc-pagination-info { font-size: 13px; color: #64748b; font-weight: 500; }
.sc-pagination-controls { display: flex; align-items: center; gap: 12px;}
.sc-page-text { font-size: 13px; font-weight: 600; color: #475569; }

.sc-btn-page {
  background: #ffffff; border: 1px solid #e2e8f0; color: #475569; border-radius: 8px; 
  cursor: pointer; transition: all 0.2s; display: flex; align-items: center; justify-content: center; width: 32px; height: 32px;
}
.sc-btn-page:hover:not([disabled]) { background: #f1f5f9; color: #1e293b; }
.sc-btn-page[disabled] { opacity: 0.3; cursor: not-allowed; }

/* --- Modal --- */
.sc-modal-overlay {
  position: fixed; top: 0; left: 0; width: 100%; height: 100%;
  background: rgba(15, 23, 42, 0.4); backdrop-filter: blur(4px);
  z-index: 9999; display: flex; justify-content: center; align-items: center;
  animation: fadeIn 0.2s ease-out; font-family: 'Poppins', 'Inter', system-ui, sans-serif;
}

.sc-modal {
  background: #ffffff; border-radius: 16px; width: 100%; max-width: 450px;
  box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
  overflow: hidden;
}

.sc-modal-header {
  display: flex; justify-content: space-between; align-items: center;
  padding: 20px 24px; border-bottom: 1px solid #f1f5f9;
}
.sc-modal-header h4 { margin: 0; font-weight: 700; color: #1e293b; font-size: 16px; }
.sc-modal-close { background: none; border: none; color: #94a3b8; font-size: 16px; cursor: pointer; transition: 0.2s; }
.sc-modal-close:hover { color: #ef4444; }

.sc-modal-body { padding: 24px; }
.sc-modal-body label { font-size: 13px; font-weight: 600; color: #475569; margin-bottom: 8px; display: block; }
.sc-textarea {
  width: 100%; height: 100px; padding: 12px; border: 1px solid #cbd5e1; border-radius: 10px;
  font-size: 14px; color: #1e293b; font-family: inherit; resize: vertical; outline: none; transition: 0.2s; box-sizing: border-box;
}
.sc-textarea:focus { border-color: #1961ED; box-shadow: 0 0 0 3px rgba(25, 97, 237, 0.1); }

.sc-modal-footer {
  padding: 16px 24px; background: #f8fafc; border-top: 1px solid #f1f5f9;
  display: flex; justify-content: flex-end; gap: 12px;
}

.sc-btn-default { background: #ffffff; border: 1px solid #cbd5e1; color: #475569; padding: 8px 16px; border-radius: 8px; font-weight: 600; font-size: 13px; cursor: pointer; transition: 0.2s; }
.sc-btn-default:hover { background: #f1f5f9; color: #1e293b; }

.sc-btn-danger { background: #ef4444; border: none; color: #ffffff; padding: 8px 16px; border-radius: 8px; font-weight: 600; font-size: 13px; cursor: pointer; transition: 0.2s; }
.sc-btn-danger:hover:not([disabled]) { background: #dc2626; }
.sc-btn-danger[disabled] { opacity: 0.5; cursor: not-allowed; }

@keyframes fadeIn { from { opacity: 0; transform: scale(0.98); } to { opacity: 1; transform: scale(1); } }

sp_widget.script:
(function() {
    var userId = gs.getUserID();

    /* rejection */
    if (input && input.action) {
        var appGr = new GlideRecord('sysapproval_approver');
        if (appGr.get(input.targetId)) {
            if (input.action == 'approve') {
                appGr.state = 'approved';
                appGr.update();
            } else if (input.action == 'reject') {
                appGr.state = 'rejected';
                appGr.comments = input.comment; // Store the mandatory comment
                appGr.update();
            }
        }
    }

    /* fetch*/
    data.approvals = [];
    var gr = new GlideRecord('sysapproval_approver');
    gr.addQuery('approver', userId);

    // filter
    if (input && input.filter == 'processed') {
        gr.addQuery('state', 'IN', 'approved,rejected');
    } else {
        gr.addQuery('state', 'requested');
    }

    // serach
    if (input && input.searchQuery) {
        var search = input.searchQuery;
        var orQuery = gr.addQuery('sysapproval.getDisplayValue()', 'CONTAINS', search);
        orQuery.addOrCondition('document_id.getDisplayValue()', 'CONTAINS', search);
    }

    gr.orderByDesc('sys_created_on');
    gr.query();

    while (gr.next()) {
        data.approvals.push({
            sys_id: gr.getUniqueValue(),
            target_id: gr.getValue('sysapproval') || gr.getValue('document_id'),
            table: gr.getValue('source_table'),
            display_name: gr.sysapproval.getDisplayValue() || "Task: " + gr.document_id.getDisplayValue(),
            state: gr.getDisplayValue('state'),
            created: gr.getDisplayValue('sys_created_on'),
            approver: gr.getDisplayValue('approver')
        });
    }
})();
